form:Form.form:Scripts:
		var nSQL;
var np;
function onLoad()
{ 
	var xmlParam = new NomadXML("PARAMS");
	xmlParam.SetAttr("oi_carpeta", Ctrl("hidOICarpeta").GetXValue());    
	np = new NomadProxy("", ut);
	nSQL = np.SQLService();
	var tipo = nSQL.GetOBJ(Ctrl("main").getResource("QRY_ULT_TIPO"), xmlParam.ToString());
	Ctrl("oi_tipo_car_ant").SetXValue(tipo.oi_tipo_carpeta);  

	var estado = nSQL.GetOBJ(Ctrl("main").getResource("QRY_ULT_ESTADO"), xmlParam.ToString());  
	Ctrl("oi_est_car_ant").SetXValue(estado.oi_estado_carpeta);	 

}    

function Aceptar()
{
	if (Ctrl("oi_tipo_car_ant").GetXValue() == Ctrl("oi_tipo_car_nu").GetXValue())
	{
		alert("Está intentando realizar un cambio al mismo tipo de carpeta");
		return false;
	}           
	else 
	{    
	  var xmlParam = new NomadXML("PARAMS"); 
	  np = new NomadProxy("", ut);
	  nSQL = np.SQLService();

	  xmlParam.SetAttr("oi_tipo_carpeta", Ctrl("oi_tipo_car_ant").GetXValue()); 
	  var c_tipo_carpeta_ant = nSQL.GetOBJ(Ctrl("main").getResource("QRY_COD_TIPO"), xmlParam.ToString()); 

	  xmlParam.SetAttr("oi_tipo_carpeta", Ctrl("oi_tipo_car_nu").GetXValue());
	  var c_tipo_carpeta_nue = nSQL.GetOBJ(Ctrl("main").getResource("QRY_COD_TIPO"), xmlParam.ToString()); 


	  if (c_tipo_carpeta_nue.c_tipo_carpeta < c_tipo_carpeta_ant.c_tipo_carpeta)
	  {
	     if(confirm("¿Está seguro de cambiar el tipo de carpeta por uno anterior?"))
  	   { 				
 				return true;    			 
  	   }
  	   else
  	   {  	   
  	   return false;
  	   } 	
	  }

		return true;
	}
}
